// idx: 23-34 = cols 92..81 (12 active right cols)
function sfRow(left15, right12){
  const e='';
  return [e, e, ...left15, e,e,e,e,e,e, ...(right12||Array(12).fill(e))];
}
function sfRowL(left15){
  return sfRow(left15, null);
}

