const _custStText  = {installed:'#006612',delivered:'#665e00',fabricated:'#ffffff',cutting:'#ffffff',cip:'#ffffff',cl_not_issued:'#8B0000',defect:'#ffffff',pending:'#224F93'};
const _custStLabel = {installed:'Installed',delivered:'Delivered',fabricated:'Fabricated',cutting:'CL Issued',cip:'CL In Prog',cl_not_issued:'CL Not Issued',defect:'Defect',pending:'Pending'};
const _custStatuses = ['pending','installed','delivered','fabricated','cutting','cip','cl_not_issued','defect'];

// In-memory cache: { 'projId|facade': { '1-A': {status,notes}, ... } }
const _custFacadeCache = {};

async function renderCustomDash(){
  const projectId = window._activeProjectId;
  const projName  = window._activeProjectName || projectId || 'Project';
  const el = document.getElementById('dash-cards');
  if(!el) return;

  el.innerHTML = `<div style="font-size:12px;color:#8099b0;padding:8px 0;">Loading overview…</div>`;

  // Load all 4 facades from Supabase
  const facades = ['NF','SF','EF','WF'];
  const _storedNames = getCustomFacadeNames(projectId);
  const facadeLabel = {NF:_storedNames.NF, SF:_storedNames.SF, EF:_storedNames.EF, WF:_storedNames.WF};
  const facadeColor = {NF:'#2d65bd', SF:'#1a9458', EF:'#e05c00', WF:'#7c3aed'};

  const {data: rows} = await sb.from('custom_project_facades')
    .select('facade,cells')
    .eq('project_id', projectId)
    .in('facade', facades);

  const byFacade = {};
  (rows||[]).forEach(r=>{ byFacade[r.facade] = r.cells||{}; });

  // Aggregate totals across all facades
  const totals = {};
  _custStatuses.forEach(s=>totals[s]=0);
  let grandTotal = 0;

  facades.forEach(f=>{
    const cells = byFacade[f]||{};
    Object.values(cells).forEach(c=>{
      const s = c.status||'pending';
      totals[s] = (totals[s]||0)+1;
      grandTotal++;
  });
  });

  // Active statuses (non-pending with data)
  const activeStatuses = _custStatuses.filter(s=>s!=='pending'&&totals[s]>0);
  const totalActive = activeStatuses.reduce((a,s)=>a+totals[s],0);
  const totalCells  = 4*10*26; // 4 facades × 10 rows × 26 cols

  // Summary cards
  const summaryCards = _custStatuses.filter(s=>s!=='pending').map(s=>`
    <div style="background:#fff;border-radius:12px;padding:16px 20px;border:1px solid rgba(34,79,147,0.1);min-width:140px;">
      <div style="font-size:11px;font-weight:700;color:#8099b0;text-transform:uppercase;letter-spacing:0.08em;margin-bottom:6px;">${_custStLabel[s]}</div>
      <div style="font-size:28px;font-weight:800;color:#1a2a3a;">${totals[s]||0}</div>
      <div style="margin-top:6px;height:4px;border-radius:2px;background:#f0f4f9;">
        <div style="height:4px;border-radius:2px;background:${_custStBg[s]};width:${totalCells?Math.round((totals[s]||0)/totalCells*100):0}%;"></div>
      </div>
      <div style="font-size:10px;color:#8099b0;margin-top:4px;">${totalCells?Math.round((totals[s]||0)/totalCells*100):0}%</div>
    </div>`).join('');

  // Per-facade breakdown
  const facadeCards = facades.map(f=>{
    const cells = byFacade[f]||{};
    const fTotals = {};
    _custStatuses.forEach(s=>fTotals[s]=0);
    Object.values(cells).forEach(c=>{ const s=c.status||'pending'; fTotals[s]=(fTotals[s]||0)+1; });
    const fActive = _custStatuses.filter(s=>s!=='pending').reduce((a,s)=>a+fTotals[s],0);
    const fTotal  = 10*26;
    const pct     = Math.round(fActive/fTotal*100);
    const bars    = _custStatuses.filter(s=>s!=='pending'&&fTotals[s]>0).map(s=>`
      <div title="${_custStLabel[s]}: ${fTotals[s]}" style="height:8px;background:${_custStBg[s]};width:${Math.round(fTotals[s]/fTotal*100)}%;border-radius:2px;"></div>`).join('');
    return `
      <div onclick="goPage('${f}')" style="background:#fff;border-radius:12px;padding:16px 20px;border:1px solid rgba(34,79,147,0.1);cursor:pointer;transition:box-shadow 0.15s;" onmouseover="this.style.boxShadow='0 4px 16px rgba(34,79,147,0.12)'" onmouseout="this.style.boxShadow=''">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
          <div style="width:10px;height:10px;border-radius:50%;background:${facadeColor[f]};flex-shrink:0;"></div>
          <div style="font-size:13px;font-weight:700;color:#1a2a3a;flex:1;">${facadeLabel[f]}</div>
          <div style="font-size:18px;font-weight:800;color:${facadeColor[f]};">${pct}%</div>
        </div>
        <div style="display:flex;gap:3px;flex-wrap:wrap;margin-bottom:6px;">${bars||'<div style="height:8px;background:#f0f4f9;border-radius:2px;width:100%;"></div>'}</div>
        <div style="font-size:11px;color:#8099b0;">${fActive} / ${fTotal} cells active</div>
      </div>`;
  }).join('');

  el.innerHTML = `
    <div style="font-family:'Barlow',sans-serif;">
      <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:24px;">${summaryCards}</div>
      <div style="font-size:10px;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:#8099b0;margin-bottom:12px;">Facades</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:12px;">${facadeCards}</div>
    </div>`;

  // Render sidebar (same as all other pages)
  const wrap = document.getElementById('dash-sidebar-wrap');
  if(wrap) wrap.innerHTML = efSidebarHTML();

  // Clear the extra facades-grid area
  const fg = document.getElementById('facades-grid');
  if(fg) fg.innerHTML='';
}

// ── All Categories overview (combined view for custom projects) ───────────────
async function renderAllCategoriesOverview(){
  const projId = window._activeProjectId;
  if(!projId || projId === 'shift-tower') return; // guard: no custom project active
  const projName = window._activeProjectName || projId || 'Project';
  const cats = initProjectCategories(projId);

  // If only one category exists, go straight to its overview (skip the extra click)
  if(cats.length === 1){
    goPage('c1-overview');
    return;
  }

  const wrap = document.getElementById('dash-sidebar-wrap');
  if(wrap) try{ wrap.innerHTML = efSidebarHTML(); }catch(e){ console.warn('efSidebarHTML error',e); }
  const fg = document.getElementById('facades-grid');
  if(fg) fg.innerHTML = '';
  const el = document.getElementById('dash-cards');
  if(!el) return;
  el.innerHTML = `<div style="font-size:12px;color:#8099b0;padding:8px 0;">Loading…</div>`;

  // Load all facade data for every category
  const allKeys = [];
  cats.forEach(cat=>['NF','SF','EF','WF'].forEach(f=>allKeys.push(cat.num===1?f:'c'+cat.num+'-'+f)));
  const {data:rows} = await sb.from('custom_project_facades').select('facade,cells').eq('project_id',projId).in('facade',allKeys);
  const byKey = {};
  (rows||[]).forEach(r=>{ byKey[r.facade]=r.cells||{}; });

  const facadeColor = {NF:'#2d65bd',SF:'#1a9458',EF:'#e05c00',WF:'#7c3aed'};
  const _metaFromCells=cells=>{ const m=cells['__meta__']; return m||{rows:Array.from({length:10}),cols:Array.from({length:26})}; };
  const catCards = cats.map(cat=>{
    const catTotals={};_custStatuses.forEach(s=>catTotals[s]=0);
    let totalCells=0;
    ['NF','SF','EF','WF'].forEach(f=>{
      const key=cat.num===1?f:'c'+cat.num+'-'+f;
      const facCells=byKey[key]||{};
      Object.entries(facCells).forEach(([k,c])=>{ if(k==='__meta__')return; const s=c.status||'pending';catTotals[s]=(catTotals[s]||0)+1; });
      const fm=_metaFromCells(facCells); totalCells+=fm.rows.length*fm.cols.length;
    });
    if(!totalCells) totalCells=4*10*26;
    const active=_custStatuses.filter(s=>s!=='pending').reduce((a,s)=>a+catTotals[s],0);
    const pct=Math.round(active/totalCells*100);
    const bars=_custStatuses.filter(s=>s!=='pending'&&catTotals[s]>0).map(s=>`<div title="${_custStLabel[s]}: ${catTotals[s]}" style="height:8px;background:${_custStBg[s]};width:${Math.max(Math.round(catTotals[s]/totalCells*100),1)}%;border-radius:2px;min-width:4px;"></div>`).join('');
    const facadeDots=['NF','SF','EF','WF'].map(f=>`<div style="display:flex;align-items:center;gap:4px;font-size:10px;color:#8099b0;"><div style="width:6px;height:6px;border-radius:50%;background:${facadeColor[f]};flex-shrink:0;"></div>${cat.facadeNames[f]}</div>`).join('');
    const catNick = cat.nick || ('CAT'+cat.num);
    return `<div onclick="goPage('c${cat.num}-overview')" style="background:#fff;border-radius:12px;padding:16px 20px;border:1px solid rgba(34,79,147,0.1);cursor:pointer;transition:box-shadow 0.15s;" onmouseover="this.style.boxShadow='0 4px 16px rgba(34,79,147,0.12)'" onmouseout="this.style.boxShadow=''">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">
        <div style="font-size:13px;font-weight:700;color:#1a2a3a;flex:1;">${cat.name}</div>
        <div onclick="event.stopPropagation();editCatNick(${cat.num})" title="Click to edit nickname"
          style="font-size:10px;font-weight:700;color:#6d35d9;background:#f3eeff;border:1px solid #d4b8ff;border-radius:6px;padding:2px 8px;cursor:pointer;flex-shrink:0;transition:background 0.15s;"
          onmouseover="this.style.background='#e8d8ff'" onmouseout="this.style.background='#f3eeff'">${catNick}</div>
        <div style="font-size:18px;font-weight:800;color:#6d35d9;">${pct}%</div>
      </div>
      <div style="display:flex;gap:3px;flex-wrap:wrap;margin-bottom:8px;">${bars||'<div style="height:8px;background:#f0f4f9;border-radius:2px;width:100%;"></div>'}</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-bottom:6px;">${facadeDots}</div>
      <div style="font-size:10px;color:#8099b0;">${active} / ${totalCells} cells active</div>
    </div>`;
  }).join('');
  el.innerHTML = `<div style="font-family:'Barlow',sans-serif;">
    <div style="font-size:10px;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:#8099b0;margin-bottom:12px;">All Categories</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:14px;">${catCards||'<div style="color:#8099b0;font-size:12px;">No categories yet.</div>'}</div>
  </div>`;
}

