function brSumif(cf){
  const base=BR_LOG_BASE_RAW.filter(r=>r[4]===cf).reduce((s,r)=>s+r[7],0);
  const custom=(brLogCustomRows||[]).filter(r=>r.po===cf).reduce((s,r)=>s+(r.montant||0),0);
  return base+custom;
}

