async function _demoImportFromMonitoring(){
  // Use the in-memory panels object (loaded from Supabase at startup via load())
  // and filter through allPanelIds() — exactly the same logic as gC() and the
  // monitoring dashboard counts.  This guarantees the demo import shows the same
  // numbers as the real monitoring view without any ID-format mismatch issues.
  const btn=document.querySelector('[onclick="_demoImportFromMonitoring()"]');
  const origText=btn?btn.innerHTML:'';
  if(btn) btn.innerHTML='<span style="opacity:0.6;font-size:11px;">Loading…</span>';

  // Small async yield so the "Loading…" text actually renders
  await new Promise(r=>setTimeout(r,30));
  if(btn) btn.innerHTML=origText;

  const validIds=allPanelIds();
  const installedIds=validIds.filter(id=>(panels[id]||{}).status==='installed');
  const deliveredIds=validIds.filter(id=>(panels[id]||{}).status==='delivered');

  if(!installedIds.length&&!deliveredIds.length){
    alert('No installed or delivered panels found in the monitoring data.');
    return;
  }

  // Find or create "Installed" legend item (green)
  const INSTALLED_COLOR='#00FF32';
  const DELIVERED_COLOR='#FFF000';

  let instItem=_demoData.legend.find(l=>l.label==='Installed');
  if(!instItem){
    instItem={id:'l_import_installed',label:'Installed',color:INSTALLED_COLOR};
    _demoData.legend.unshift(instItem); // add at top
  }

  let delivItem=_demoData.legend.find(l=>l.label==='Delivered');
  if(!delivItem){
    delivItem={id:'l_import_delivered',label:'Delivered',color:DELIVERED_COLOR};
    // Insert after Installed
    const instIdx=_demoData.legend.indexOf(instItem);
    _demoData.legend.splice(instIdx+1,0,delivItem);
  }

  // Assign panel IDs to legend items (overwrites any previous demo colour for those panels)
  installedIds.forEach(id=>{ _demoData.panels[id]=instItem.id; });
  deliveredIds.forEach(id=>{ _demoData.panels[id]=delivItem.id; });

  // Propagate corner-adjustment mirrors so hidden boundary columns get the same colour
  // as their masters: SF-15→WF-15, NF-31→WF-31, NF-65→EF-65, SF-81→EF-81
  installedIds.concat(deliveredIds).forEach(id=>{
    const _lid=_demoData.panels[id]; if(!_lid) return;
    const _sf15=id.match(/^SF-(.+)-C15$/); if(_sf15) _demoData.panels[`WF-${_sf15[1]}-C15`]=_lid;
    const _nf31=id.match(/^NF-(.+)-C31$/); if(_nf31) _demoData.panels[`WF-${_nf31[1]}-C31`]=_lid;
    const _nf65=id.match(/^NF-(.+)-C65$/); if(_nf65) _demoData.panels[`EF-${_nf65[1]}-C65`]=_lid;
    const _sf81=id.match(/^SF-(.+)-C81$/); if(_sf81) _demoData.panels[`EF-${_sf81[1]}-C81`]=_lid;
  });

  // Refresh view
  _demoRenderLegend();
  _demoRenderGrid();

  const total=installedIds.length+deliveredIds.length;
  // Brief toast confirmation
  const toast=document.createElement('div');
  toast.style.cssText='position:fixed;bottom:28px;left:50%;transform:translateX(-50%);background:#1a2a3a;color:#fff;font-size:12px;font-weight:600;padding:9px 20px;border-radius:20px;z-index:99999;pointer-events:none;opacity:1;transition:opacity 0.4s;';
  toast.textContent='✓ Imported '+installedIds.length+' installed · '+deliveredIds.length+' delivered ('+total+' panels total)';
  document.body.appendChild(toast);
  setTimeout(()=>{toast.style.opacity='0';setTimeout(()=>document.body.removeChild(toast),400);},2800);
}

// ── Legend fit helper ────────────────────────────────────────
// Shrinks font / swatch / padding on ._leg-pill elements inside `legRow`
// until all items fit within 2 flex rows (or until min font 6px is reached).
// constrainPx: temporarily limits legRow width to the actual print content width
// so the flex-wrap is evaluated at print dimensions, not screen dimensions.
function _demoFitLegRow(legRow, constrainPx){
  var pills=Array.from(legRow.querySelectorAll('._leg-pill'));
  if(!pills.length) return;
  // Apply print-width constraint so measurement matches real print layout
  if(constrainPx){
    legRow.style.maxWidth=constrainPx+'px';
    void legRow.offsetHeight; // force reflow at print width
  }
  var firstH=pills[0].offsetHeight;
  var maxH=firstH*2+10; // 2 rows + gap/tolerance
  var fs=10, ss=10;
  while(legRow.scrollHeight>maxH && fs>6){
    fs=parseFloat((fs-0.5).toFixed(1));
    ss=Math.max(6,parseFloat((ss-0.5).toFixed(1)));
    pills.forEach(function(p){
      p.querySelectorAll('span').forEach(function(s){s.style.fontSize=fs+'px';});
      var sw=p.querySelector('._leg-swatch');
      if(sw){sw.style.width=ss+'px';sw.style.height=ss+'px';}
      p.style.padding=(fs<7.5?'1px 5px':fs<8.5?'2px 7px':'3px 9px');
    });
  }
  // Keep max-width on so the leg container stays at print width for height measurement
}

