// BETA VERSION
// ══════════════════════════════════════════════════════════════
function renderBetaPage(){
  const el=document.getElementById('page-beta');
  if(!el)return;

  const features=[
    {icon:'🧊',label:'3D View',       color:'#0ea5e9',bg:'#e0f2fe',desc:'View the building model in interactive 3D',   action:`goPage('3d')`},
    {icon:'🏗',label:'3D Builder',    color:'#f59e0b',bg:'#fef3c7',desc:'Build and arrange 3D shapes freely',           action:`goPage('builder')`},
    {icon:'📸',label:'Site Pictures', color:'#f97316',bg:'#ffedd5',desc:'Photo gallery from the construction site',     action:`goPage('sitepictures')`},
  ];

  const cards=features.map(f=>`
    <div onclick="${f.action}"
      style="background:#fff;border:1.5px solid #e5e7eb;border-radius:14px;padding:22px 20px;cursor:pointer;display:flex;flex-direction:column;gap:10px;transition:all 0.18s;box-shadow:0 1px 4px rgba(0,0,0,0.05);"
      onmouseover="this.style.borderColor='${f.color}';this.style.boxShadow='0 4px 18px ${f.color}28';this.style.transform='translateY(-2px)'"
      onmouseout="this.style.borderColor='#e5e7eb';this.style.boxShadow='0 1px 4px rgba(0,0,0,0.05)';this.style.transform='translateY(0)'">
      <div style="width:46px;height:46px;border-radius:12px;background:${f.bg};display:flex;align-items:center;justify-content:center;font-size:22px;">${f.icon}</div>
      <div>
        <div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:3px;">${f.label}</div>
        <div style="font-size:11px;color:var(--text3);line-height:1.45;">${f.desc}</div>
      </div>
      <div style="margin-top:auto;font-size:11px;font-weight:600;color:${f.color};display:flex;align-items:center;gap:4px;">Open ›</div>
    </div>`).join('');

  el.innerHTML=`
    <div style="display:flex;flex-direction:column;height:100%;background:var(--bg);overflow-y:auto;">
      <!-- Header -->
      <div style="padding:22px 28px 16px;border-bottom:1px solid var(--border);background:var(--surface);flex-shrink:0;">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;">
          <span style="font-size:22px;">🧪</span>
          <span style="font-size:16px;font-weight:700;color:var(--text);">Beta Features</span>
          <span style="font-size:10px;font-weight:700;padding:2px 8px;border-radius:20px;background:#fce7eb;color:#f43f5e;letter-spacing:.04em;">BETA</span>
        </div>
        <div style="font-size:11px;color:var(--text3);margin-left:32px;">Experimental and upcoming features — may change at any time</div>
      </div>
      <!-- Grid -->
      <div style="padding:24px 28px;display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:16px;">
        ${cards}
        <!-- HR card with sub-options -->
        <div style="background:#fff;border:1.5px solid #e5e7eb;border-radius:14px;padding:22px 20px;display:flex;flex-direction:column;gap:10px;box-shadow:0 1px 4px rgba(0,0,0,0.05);">
          <div style="width:46px;height:46px;border-radius:12px;background:#fee2e2;display:flex;align-items:center;justify-content:center;font-size:22px;">👥</div>
          <div>
            <div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:3px;">Human Resources</div>
            <div style="font-size:11px;color:var(--text3);line-height:1.45;">Time sheets and labor planning</div>
          </div>
          <div style="display:flex;flex-direction:column;gap:6px;margin-top:4px;">
            <button onclick="goPage('labor-curve')"
              style="padding:7px 12px;border:1.5px solid #e5e7eb;border-radius:8px;background:#fafafa;cursor:pointer;font-size:11px;font-weight:600;color:#e53935;text-align:left;font-family:inherit;transition:all 0.15s;"
              onmouseover="this.style.borderColor='#e53935';this.style.background='#fef2f2'"
              onmouseout="this.style.borderColor='#e5e7eb';this.style.background='#fafafa'">📈 Labor Curve</button>
            <button disabled
              style="padding:7px 12px;border:1.5px solid #e5e7eb;border-radius:8px;background:#fafafa;font-size:11px;font-weight:600;color:#94a3b8;text-align:left;font-family:inherit;cursor:not-allowed;display:flex;align-items:center;justify-content:space-between;">
              <span>🗓 Time Sheet</span>
              <span style="font-size:9px;background:#f1f5f9;padding:1px 6px;border-radius:10px;">Soon</span>
            </button>
          </div>
        </div>
      </div>
    </div>`;
}

// ══════════════════════════════════════════════════════════════
// AGENDA — monthly calendar with tasks
// ══════════════════════════════════════════════════════════════
function renderAgendaPage(){
  const el=document.getElementById('page-agenda');
  if(!el)return;
  const now=new Date();
  if(!window._ag) window._ag={y:now.getFullYear(),m:now.getMonth(),tasks:{},employees:[]};

  const bs='border:1px solid var(--border);background:var(--surface2);color:var(--text);border-radius:6px;cursor:pointer;font-size:12px;font-family:inherit;';
  el.innerHTML=
    '<div style="display:flex;flex-direction:column;height:100%;background:var(--bg);position:relative;overflow:hidden;">'+
      '<div style="display:flex;align-items:center;gap:8px;padding:9px 16px;background:var(--surface);border-bottom:1px solid var(--border);flex-shrink:0;">'+
        '<button onclick="_agNav(-1)" style="'+bs+'padding:3px 11px;font-size:15px;">&#8249;</button>'+
        '<span id="ag-title" style="font-size:14px;font-weight:700;color:var(--text);min-width:160px;text-align:center;"></span>'+
        '<button onclick="_agNav(1)"  style="'+bs+'padding:3px 11px;font-size:15px;">&#8250;</button>'+
        '<button onclick="_agToday()" style="'+bs+'padding:4px 12px;margin-left:4px;">Today</button>'+
        '<span style="flex:1;"></span>'+
        '<button onclick="_agOpenTeam()" style="'+bs+'padding:4px 12px;display:flex;align-items:center;gap:5px;">&#128101; Team</button>'+
        '<span id="ag-loading" style="font-size:11px;color:var(--text3);margin-left:8px;display:none;">Loading…</span>'+
      '</div>'+
      '<div style="display:grid;grid-template-columns:repeat(7,1fr);background:var(--surface);border-bottom:1px solid var(--border);flex-shrink:0;">'+
        ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].map(d=>
          '<div style="text-align:center;padding:5px 0;font-size:10px;font-weight:700;color:var(--text3);letter-spacing:.5px;">'+d+'</div>'
        ).join('')+
      '</div>'+
      '<div id="ag-cal" style="flex:1;overflow-y:auto;display:grid;grid-template-columns:repeat(7,1fr);align-content:start;"></div>'+
      // ── task add/edit modal ──
      '<div id="ag-modal" style="display:none;position:absolute;inset:0;background:rgba(0,0,0,0.45);z-index:200;align-items:center;justify-content:center;" onclick="if(event.target===this)document.getElementById(\'ag-modal\').style.display=\'none\'">'+
        '<div style="background:var(--surface);border-radius:12px;padding:22px;width:310px;box-shadow:0 8px 32px rgba(0,0,0,0.28);" onclick="event.stopPropagation()">'+
          '<div id="ag-modal-title" style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:4px;">&#128197; Add Task</div>'+
          '<div id="ag-modal-date" style="font-size:10px;color:var(--text3);margin-bottom:14px;"></div>'+
          '<input id="ag-task-id"   type="hidden">'+
          '<input id="ag-task-date" type="hidden">'+
          '<div style="margin-bottom:10px;">'+
            '<label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px;">Task</label>'+
            '<input id="ag-task-txt" placeholder="Task description…" style="width:100%;box-sizing:border-box;padding:7px 10px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg);color:var(--text);font-family:inherit;outline:none;" onkeydown="if(event.key===\'Enter\')_agSaveTask()">'+
          '</div>'+
          '<div style="margin-bottom:18px;">'+
            '<label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px;">Assign to</label>'+
            '<select id="ag-task-who" style="width:100%;box-sizing:border-box;padding:7px 10px;font-size:12px;border:1px solid var(--border);border-radius:6px;background:var(--bg);color:var(--text);font-family:inherit;outline:none;">'+
              '<option value="">&#8212; Unassigned &#8212;</option>'+
            '</select>'+
          '</div>'+
          '<div style="display:flex;gap:8px;justify-content:flex-end;">'+
            '<button onclick="document.getElementById(\'ag-modal\').style.display=\'none\'" style="'+bs+'padding:6px 14px;">Cancel</button>'+
            '<button onclick="_agSaveTask()" style="background:#10b981;color:#fff;border:none;border-radius:6px;padding:6px 18px;font-size:12px;cursor:pointer;font-family:inherit;font-weight:600;">Save</button>'+
          '</div>'+
        '</div>'+
      '</div>'+
      // ── team modal ──
      '<div id="ag-team-modal" style="display:none;position:absolute;inset:0;background:rgba(0,0,0,0.45);z-index:200;align-items:center;justify-content:center;" onclick="if(event.target===this)document.getElementById(\'ag-team-modal\').style.display=\'none\'">'+
        '<div style="background:var(--surface);border-radius:12px;width:360px;max-height:80vh;display:flex;flex-direction:column;box-shadow:0 8px 32px rgba(0,0,0,0.28);overflow:hidden;" onclick="event.stopPropagation()">'+
          '<div id="ag-team-content" style="flex:1;overflow-y:auto;display:flex;flex-direction:column;min-height:0;"></div>'+
        '</div>'+
      '</div>'+
    '</div>';

  _agLoad();
}

async function _agLoad(){
  const loadEl=document.getElementById('ag-loading');
  if(loadEl) loadEl.style.display='inline';
  try{
    const [{data:tData,error:tErr},{data:eData,error:eErr}]=await Promise.all([
      sb.from('agenda_tasks').select('*').order('created_at',{ascending:true}),
      sb.from('profiles').select('id,full_name,username,role,status').order('full_name',{ascending:true})
    ]);
    if(tErr) throw tErr;
    if(eErr) throw eErr;
    const tasks={};
    (tData||[]).forEach(r=>{
      if(!tasks[r.date]) tasks[r.date]=[];
      tasks[r.date].push({id:r.id,text:r.text,who:r.who||'',done:r.done});
    });
    window._ag.tasks=tasks;
    // Only include active (non-pending, non-suspended) users
    window._ag.employees=(eData||[])
      .filter(r=>r.status!=='pending'&&r.status!=='suspended')
      .map(r=>({id:r.id,name:r.full_name||r.username||r.id,role:r.role}));
  }catch(e){
    console.error('Agenda load error:',e);
    if(!window._ag.tasks) window._ag.tasks={};
    if(!window._ag.employees) window._ag.employees=[];
  }
  if(loadEl) loadEl.style.display='none';
  _agDraw();
}

function _agNav(dir){
  const a=window._ag; a.m+=dir;
  if(a.m<0){a.m=11;a.y--;} if(a.m>11){a.m=0;a.y++;}
  _agLoad();
}
function _agToday(){const n=new Date();window._ag.y=n.getFullYear();window._ag.m=n.getMonth();_agLoad();}

function _agDraw(){
  const {y,m,tasks}=window._ag;
  const MONTHS=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const titleEl=document.getElementById('ag-title');
  const cal=document.getElementById('ag-cal');
  if(!titleEl||!cal) return;
  titleEl.textContent=MONTHS[m]+' '+y;

  const n=new Date();
  const todayStr=n.getFullYear()+'-'+String(n.getMonth()+1).padStart(2,'0')+'-'+String(n.getDate()).padStart(2,'0');
  const firstDow=new Date(y,m,1).getDay();
  const startOffset=(firstDow+6)%7;
  const daysInMonth=new Date(y,m+1,0).getDate();

  let html='';
  for(let i=0;i<startOffset;i++)
    html+='<div style="min-height:110px;border:1px solid var(--border);background:var(--bg);opacity:0.25;"></div>';

  for(let d=1;d<=daysInMonth;d++){
    const ds=y+'-'+String(m+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    const isToday=ds===todayStr;
    const dayTasks=tasks[ds]||[];
    const taskRows=dayTasks.map(t=>{
      const doneStyle=t.done?'text-decoration:line-through;color:#94a3b8;':'color:var(--text);';
      return '<div style="display:flex;align-items:flex-start;gap:4px;padding:2px 0;border-bottom:1px solid var(--border);">'+
        '<button onclick="_agToggle(\''+t.id+'\','+t.done+')" title="'+(t.done?'Mark undone':'Mark done')+'" '+
          'style="flex-shrink:0;width:13px;height:13px;border-radius:50%;border:1.5px solid '+(t.done?'#10b981':'#94a3b8')+';background:'+(t.done?'#10b981':'transparent')+';cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;margin-top:2px;">'+
          (t.done?'<span style="color:#fff;font-size:8px;line-height:1;">&#10003;</span>':'')+
        '</button>'+
        '<div style="flex:1;min-width:0;">'+
          '<div style="font-size:10px;'+doneStyle+'line-height:1.35;word-break:break-word;">'+_agEsc(t.text)+'</div>'+
          (t.who?'<button onclick="_agShowEmployee(\''+t.who.replace(/'/g,"\\'")+'\')" style="font-size:9px;color:#10b981;font-weight:600;margin-top:1px;background:none;border:none;cursor:pointer;padding:0;font-family:inherit;text-decoration:underline;text-underline-offset:2px;">'+_agEsc(t.who)+'</button>':'')+
        '</div>'+
        '<button onclick="_agOpenEdit(\''+t.id+'\')" title="Edit" '+
          'style="flex-shrink:0;background:none;border:none;color:#94a3b8;cursor:pointer;font-size:10px;line-height:1;padding:0 1px;" onmouseover="this.style.color=\'#224F93\'" onmouseout="this.style.color=\'#94a3b8\'">&#9998;</button>'+
        '<button onclick="_agDelete(\''+t.id+'\')" title="Remove" '+
          'style="flex-shrink:0;background:none;border:none;color:#94a3b8;cursor:pointer;font-size:12px;line-height:1;padding:0;">&#215;</button>'+
      '</div>';
    }).join('');

    html+=
      '<div style="min-height:110px;border:1px solid var(--border);background:'+(isToday?'rgba(16,185,129,0.06)':'var(--surface)')+';padding:5px;display:flex;flex-direction:column;">'+
        '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;">'+
          '<span style="font-size:11px;font-weight:'+(isToday?'700':'500')+';'+(isToday?
            'background:#10b981;color:#fff;border-radius:50%;width:18px;height:18px;display:inline-flex;align-items:center;justify-content:center;':
            'color:var(--text2);')+'">'+ d +'</span>'+
          '<button onclick="_agOpen(\''+ds+'\')" title="Add task" style="background:none;border:none;color:#10b981;cursor:pointer;font-size:17px;line-height:1;padding:0 2px;">+</button>'+
        '</div>'+
        '<div style="display:flex;flex-direction:column;gap:2px;flex:1;">'+taskRows+'</div>'+
      '</div>';
  }

  const total=startOffset+daysInMonth;
  const rem=total%7;
  if(rem>0) for(let i=0;i<7-rem;i++)
    html+='<div style="min-height:110px;border:1px solid var(--border);background:var(--bg);opacity:0.25;"></div>';

  cal.innerHTML=html;
}

function _agEsc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}

// ── populate the assign select ───────────────────────────────
function _agPopulateSelect(selectedWho){
  const sel=document.getElementById('ag-task-who');
  if(!sel) return;
  const emps=window._ag.employees||[];
  let opts='<option value="">&#8212; Unassigned &#8212;</option>';
  emps.forEach(e=>{
    opts+='<option value="'+_agEsc(e.name)+'"'+(e.name===selectedWho?' selected':'')+'>'+_agEsc(e.name)+'</option>';
  });
  if(selectedWho&&!emps.find(e=>e.name===selectedWho))
    opts+='<option value="'+_agEsc(selectedWho)+'" selected>'+_agEsc(selectedWho)+' (removed)</option>';
  sel.innerHTML=opts;
}

// ── open modal for adding ─────────────────────────────────────
function _agOpen(ds){
  document.getElementById('ag-task-id').value='';
  document.getElementById('ag-task-date').value=ds;
  document.getElementById('ag-task-txt').value='';
  _agPopulateSelect('');
  const parts=ds.split('-');
  const label=new Date(+parts[0],+parts[1]-1,+parts[2]).toLocaleDateString(undefined,{weekday:'long',day:'numeric',month:'long',year:'numeric'});
  document.getElementById('ag-modal-title').textContent='📅 Add Task';
  document.getElementById('ag-modal-date').textContent=label;
  document.getElementById('ag-modal').style.display='flex';
  setTimeout(()=>document.getElementById('ag-task-txt').focus(),60);
}

// ── open modal for editing ────────────────────────────────────
function _agOpenEdit(taskId){
  const ag=window._ag;
  let task=null,taskDate=null;
  for(const ds in ag.tasks){const t=ag.tasks[ds].find(t=>t.id===taskId);if(t){task=t;taskDate=ds;break;}}
  if(!task) return;
  document.getElementById('ag-task-id').value=taskId;
  document.getElementById('ag-task-date').value=taskDate;
  document.getElementById('ag-task-txt').value=task.text;
  _agPopulateSelect(task.who);
  const parts=taskDate.split('-');
  const label=new Date(+parts[0],+parts[1]-1,+parts[2]).toLocaleDateString(undefined,{weekday:'long',day:'numeric',month:'long',year:'numeric'});
  document.getElementById('ag-modal-title').textContent='✏️ Edit Task';
  document.getElementById('ag-modal-date').textContent=label;
  document.getElementById('ag-modal').style.display='flex';
  setTimeout(()=>document.getElementById('ag-task-txt').focus(),60);
}

// ── save task (add or edit) ───────────────────────────────────
async function _agSaveTask(){
  const txt=document.getElementById('ag-task-txt').value.trim();
  if(!txt) return;
  const existingId=document.getElementById('ag-task-id').value;
  const ds=document.getElementById('ag-task-date').value;
  const who=document.getElementById('ag-task-who').value;
  document.getElementById('ag-modal').style.display='none';
  const ag=window._ag;

  if(existingId){
    // Edit mode — optimistic
    for(const d in ag.tasks){const t=ag.tasks[d].find(t=>t.id===existingId);if(t){t.text=txt;t.who=who;break;}}
    _agDraw();
    try{
      const {error}=await sb.from('agenda_tasks').update({text:txt,who}).eq('id',existingId);
      if(error) throw error;
    }catch(e){console.error('Edit task error:',e);await _agLoad();alert('Failed to update task.');}
  } else {
    // Add mode — optimistic
    const id=Date.now().toString(36)+Math.random().toString(36).slice(2,7);
    if(!ag.tasks[ds]) ag.tasks[ds]=[];
    ag.tasks[ds].push({id,text:txt,who,done:false});
    _agDraw();
    try{
      const {error}=await sb.from('agenda_tasks').insert({id,date:ds,text:txt,who,done:false});
      if(error) throw error;
    }catch(e){
      console.error('Agenda save error:',e);
      ag.tasks[ds]=ag.tasks[ds].filter(t=>t.id!==id);
      _agDraw();
      alert('Failed to save task. Please try again.');
    }
  }
}

async function _agToggle(id,currentDone){
  const newDone=!currentDone;
  const ag=window._ag;
  for(const ds in ag.tasks){const t=ag.tasks[ds].find(t=>t.id===id);if(t){t.done=newDone;break;}}
  _agDraw();
  try{
    const {error}=await sb.from('agenda_tasks').update({done:newDone}).eq('id',id);
    if(error) throw error;
  }catch(e){
    console.error('Agenda toggle error:',e);
    for(const ds in ag.tasks){const t=ag.tasks[ds].find(t=>t.id===id);if(t){t.done=currentDone;break;}}
    _agDraw();
  }
}

async function _agDelete(id){
  const ag=window._ag;
  let removed=null,removedDate=null;
  for(const ds in ag.tasks){
    const idx=ag.tasks[ds].findIndex(t=>t.id===id);
    if(idx>-1){removed=ag.tasks[ds][idx];removedDate=ds;ag.tasks[ds].splice(idx,1);break;}
  }
  _agDraw();
  try{
    const {error}=await sb.from('agenda_tasks').delete().eq('id',id);
    if(error) throw error;
  }catch(e){
    console.error('Agenda delete error:',e);
    if(removed&&removedDate){if(!ag.tasks[removedDate])ag.tasks[removedDate]=[];ag.tasks[removedDate].push(removed);}
    _agDraw();
  }
}

// ── team modal ────────────────────────────────────────────────
function _agOpenTeam(){
  _agRenderTeamList();
  document.getElementById('ag-team-modal').style.display='flex';
}

function _agRenderTeamList(){
  const emps=window._ag.employees||[];
  const ag=window._ag;
  let html=
    '<div style="display:flex;align-items:center;justify-content:space-between;padding:14px 18px;border-bottom:1px solid var(--border);flex-shrink:0;">'+
      '<span style="font-size:13px;font-weight:700;color:var(--text);">&#128101; Team</span>'+
      '<button onclick="document.getElementById(\'ag-team-modal\').style.display=\'none\'" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:16px;line-height:1;">&#215;</button>'+
    '</div>';

  if(emps.length===0){
    html+='<div style="padding:24px;text-align:center;color:var(--text3);font-size:12px;">No active users found.</div>';
  } else {
    html+='<div style="flex:1;overflow-y:auto;">';
    emps.forEach(e=>{
      let total=0,done=0;
      for(const ds in ag.tasks) ag.tasks[ds].forEach(t=>{if(t.who===e.name){total++;if(t.done)done++;}});
      const roleLabel=e.role&&e.role!=='viewer'?'<span style="font-size:9px;background:#e0e7ff;color:#4338ca;border-radius:3px;padding:1px 5px;font-weight:600;text-transform:uppercase;">'+_agEsc(e.role)+'</span>':'';
      html+=
        '<div style="display:flex;align-items:center;gap:8px;padding:10px 16px;border-bottom:1px solid var(--border);cursor:pointer;" onmouseover="this.style.background=\'var(--surface2)\'" onmouseout="this.style.background=\'\'" onclick="_agShowEmployee(\''+e.name.replace(/'/g,"\\'")+'\')">'+
          '<div style="width:32px;height:32px;border-radius:50%;background:#224F93;color:#fff;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;flex-shrink:0;">'+
            _agEsc(e.name.charAt(0).toUpperCase())+
          '</div>'+
          '<div style="flex:1;min-width:0;">'+
            '<div style="display:flex;align-items:center;gap:6px;">'+
              '<span style="font-size:12px;font-weight:600;color:var(--text);">'+_agEsc(e.name)+'</span>'+
              roleLabel+
            '</div>'+
            '<div style="font-size:10px;color:var(--text3);margin-top:2px;">'+
              (total?total+' task'+(total!==1?'s':'')+' &middot; '+done+' done':'No tasks assigned')+
            '</div>'+
          '</div>'+
          '<span style="color:var(--text3);font-size:14px;">&#8250;</span>'+
        '</div>';
    });
    html+='</div>';
  }
  document.getElementById('ag-team-content').innerHTML=html;
}

function _agShowEmployee(name){
  const ag=window._ag;
  const allTasks=[];
  for(const ds in ag.tasks) ag.tasks[ds].forEach(t=>{if(t.who===name)allTasks.push({...t,date:ds});});
  allTasks.sort((a,b)=>a.date.localeCompare(b.date));
  const pending=allTasks.filter(t=>!t.done);
  const done=allTasks.filter(t=>t.done);

  const fmtDate=ds=>{const p=ds.split('-');return new Date(+p[0],+p[1]-1,+p[2]).toLocaleDateString(undefined,{weekday:'short',day:'numeric',month:'short'});};

  let html=
    '<div style="display:flex;align-items:center;gap:8px;padding:12px 16px;border-bottom:1px solid var(--border);flex-shrink:0;">'+
      '<button onclick="_agRenderTeamList()" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:18px;line-height:1;padding:0 4px 0 0;">&#8592;</button>'+
      '<span style="font-size:13px;font-weight:700;color:var(--text);flex:1;">'+_agEsc(name)+'</span>'+
      '<button onclick="document.getElementById(\'ag-team-modal\').style.display=\'none\'" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:16px;line-height:1;">&#215;</button>'+
    '</div>'+
    '<div style="padding:10px 16px;border-bottom:1px solid var(--border);flex-shrink:0;">'+
      '<span style="font-size:11px;color:var(--text3);">'+pending.length+' pending &nbsp;&middot;&nbsp; '+done.length+' completed</span>'+
    '</div>';

  if(allTasks.length===0){
    html+='<div style="padding:24px;text-align:center;color:var(--text3);font-size:12px;">No tasks assigned to '+_agEsc(name)+'</div>';
  } else {
    html+='<div style="flex:1;overflow-y:auto;padding:10px 0;">';
    if(pending.length>0){
      html+='<div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.6px;padding:4px 16px 6px;">Pending</div>';
      pending.forEach(t=>{
        html+='<div style="display:flex;align-items:flex-start;gap:8px;padding:7px 16px;border-bottom:1px solid var(--border);">'+
          '<div style="width:7px;height:7px;border-radius:50%;background:#f59e0b;flex-shrink:0;margin-top:4px;"></div>'+
          '<div style="flex:1;font-size:11px;color:var(--text);line-height:1.4;">'+_agEsc(t.text)+'</div>'+
          '<div style="font-size:10px;color:var(--text3);white-space:nowrap;">'+fmtDate(t.date)+'</div>'+
        '</div>';
      });
    }
    if(done.length>0){
      html+='<div style="font-size:10px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.6px;padding:'+(pending.length?'10px':'4px')+' 16px 6px;">Completed</div>';
      done.forEach(t=>{
        html+='<div style="display:flex;align-items:flex-start;gap:8px;padding:7px 16px;border-bottom:1px solid var(--border);">'+
          '<div style="width:7px;height:7px;border-radius:50%;background:#10b981;flex-shrink:0;margin-top:4px;"></div>'+
          '<div style="flex:1;font-size:11px;color:#94a3b8;text-decoration:line-through;line-height:1.4;">'+_agEsc(t.text)+'</div>'+
          '<div style="font-size:10px;color:var(--text3);white-space:nowrap;">'+fmtDate(t.date)+'</div>'+
        '</div>';
      });
    }
    html+='</div>';
  }
  document.getElementById('ag-team-content').innerHTML=html;
}


// ══════════════════════════════════════════════════════════════
// AAA — 3D Facade Box Overview
// ══════════════════════════════════════════════════════════════
function renderAAAPage(){
  const el=document.getElementById('page-aaa');
  if(!el)return;

  // Custom projects: show blank page
  if(window._activeProjectId && window._activeProjectId!=='shift-tower'){
    el.innerHTML=`<div style="display:flex;flex-direction:column;align-items:center;justify-content:center;height:100%;gap:16px;font-family:'Barlow',sans-serif;color:#8099b0;">
      <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#b0bec5" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/></svg>
      <div style="font-size:15px;font-weight:600;">3D not configured for this project</div>
      <div style="font-size:12px;">The 3D view will be set up individually for each project.</div>
    </div>`;
    return;
  }

  const CELL=7;            // px per panel column width in 3D
  const GAP=1;             // px joint between panels
  const JOINT='#07111e';   // joint / structural-gap colour
  const BASE_H=150;        // actual table row height for a normal floor (px)
  const BASE_W=50;         // actual table column width (px) — gives 150:50 = 3:1 ratio

  // Actual table row heights per special floor (mirrors buildComplexTable)
  const TABLE_ROW_H={
    'R+34':166,'R+18T':25,'R+18M':50,'R+18MD':110,
    'R+18B':40,'R+17T':50,'R+17B':100,
                              // R+02 and R+01 both use normal height (BASE_H) — per-section overrides below
  };
  // Floors that carry no UCW panels — rendered as a structural band
  const STRUCT_FLOORS=new Set(['R+18M','R+18MD','R+18B']);
  // R+17T is NOT structural — WF has real UCW panels there (C1702, R17xx types)

  // Scale a table-px height to 3D-px height, respecting the 150×50 actual ratio
  // Standard floor: round(150 * 7 / 50) = 21px  (= 3× the 7px column width ✓)
  function rowPx(fl){
    return Math.max(2,Math.round((TABLE_ROW_H[fl]||BASE_H)*CELL/BASE_W));
  }

  // Total 3D height of a floor list
  function totalH(floors){
    return floors.reduce((s,fl)=>s+rowPx(fl),0)+(floors.length-1)*GAP;
  }

  const SC={
    installed:'#00FF32',delivered:'#FFF000',fabricated:'#002DFF',
    cutting:'#C98BCA',cip:'#A349A4',cl_not_issued:'#FFB3B3',
    defect:'#ED1C24',pending:'#E8F0FB'
  };
  const STRUCT_CLR='#1c1000'; // colour for structural/mechanical band rows

  // ── Column width helpers ─────────────────────────────────────
  function colsW(n){return n*CELL+(n-1)*GAP;}

  // Strip corner-adjustment cols for 3D (WF drops '15-A', SF drops '15-A'+'15-B')
  const sfCols3D=SF_COLS.filter(c=>c!=='15-A'&&c!=='15-B'); // 35→33
  const wfCols3D=WF_COLS.filter(c=>c!=='15-A');              // 18→17
  const sfTypes3D={},wfTypes3D={};
  SF_FLOORS.forEach(fl=>{sfTypes3D[fl]=(SF_TYPES[fl]||[]).slice(2);});
  WF_FLOORS.forEach(fl=>{wfTypes3D[fl]=(WF_TYPES[fl]||[]).slice(0,-1);});

  const sfW=colsW(sfCols3D.length); // 33→296
  const nfW=colsW(NF_COLS.length);  // 33→296
  const efW=colsW(EF_COLS.length);  // 17→152
  const wfW=colsW(wfCols3D.length); // 17→152
  const fH =totalH(SF_FLOORS);     // shared floor list → same H for all faces

  const W=Math.max(sfW,nfW); // east-west box half-width → 314
  const D=Math.max(efW,wfW); // north-south box half-depth → 161

  // ── Build a face grid with correct variable row heights ──────
  function faceGrid(zid,cols,floors,types,extraRowH,merges){
    function faceRowPx(fl){
      if(extraRowH&&extraRowH[fl]!=null)return Math.max(2,Math.round(extraRowH[fl]*CELL/BASE_W));
      return rowPx(fl);
    }
    const rowHeights=floors.map(faceRowPx);
    const colTpl=Array(cols.length).fill(`${CELL}px`).join(' ');
    const rowTpl=rowHeights.map(h=>`${h}px`).join(' ');
    const w=colsW(cols.length);
    const h=rowHeights.reduce((s,rh)=>s+rh,0)+(floors.length-1)*GAP;

    const DOTS   =`radial-gradient(circle,rgba(0,0,0,0.28) 1px,transparent 1px) 0 0/4px 4px`;
    const STRIPES=`repeating-linear-gradient(90deg,rgba(0,0,0,0.28) 0,rgba(0,0,0,0.28) 1px,transparent 1px,transparent 4px)`;
    const redL=`border-left:2px solid #ED1C24;`;
    const redB=`border-bottom:1px solid #ED1C24;`;

    // ── Shorthand pattern strings ─────────────────────────────────────────────
    const _sp=`background-image:linear-gradient(180deg,rgba(255,255,255,0.18) 0 33%,transparent 33%);`;
    const _2c=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%),${STRIPES};`;
    const _2cf=`background-image:linear-gradient(90deg,transparent 50%,rgba(0,0,0,0.18) 50%),${STRIPES};`;
    const _st=`background-image:${STRIPES};`;
    const _dt=`background-image:${DOTS};`;
    const redR=`border-right:2px solid #ED1C24;`;
    // ── Type-pattern map for C, D, E, G, M variants ──────────────────────────
    const _TM={
      // C types
      'C01':_sp,       'C02':_sp+redB,  'C03':_sp,       'C04':_sp+redB,
      'C05':_sp,       'C06':_sp+redB,  'C07':_sp,       'C08':_sp+redB,
      'C09':_sp,       'C10':_sp+redB,
      'C101':_st,      'C102':_st+redL,
      'C1902':_sp,
      // D types
      'D01':_sp,       'D02':_sp+redB,  'D03':_sp+redL,  'D04':_sp+redL+redB,
      'D05':_st+redL,  'D06':_st+redL+redB, 'DM06':_st+redL,
      'D07':_2c,       'D08':_2c+redL,  'D09':_2cf+redL, 'D10':_2c+redB,
      'D11':_2c+redL+redB, 'D12':_2cf+redL+redB,
      // E types
      'E01':_sp,       'E02':_sp+redB,  'E03':_sp+redL,  'E04':_sp+redL+redB,
      'E05':_st+redL,  'E06':_st+redL+redB,
      'E07':_2c,       'E08':_2c+redL,  'E09':_2cf+redL, 'E10':_2c+redB,
      'E11':_2c+redL+redB, 'E12':_2cf+redL+redB,
      // G types
      'G03':_sp+redL,  'G04':_sp+redL+redB, 'G05':_st+redL, 'G06':_st+redL+redB,
      'GM06':_st+redL,
      // M types
      'M06':_st+redL,  'M10':_2c,       'M11':_2c+redL,  'M12':_2cf+redL,
      // R2xx / C2xx / E202  (R+01 short floor — 25 px in table)
      'R201':_dt,      'C201':_dt,
      'R202':_dt+redL, 'E202':_dt+redL+redR,
      'R203':_st+redL,
      'R204':_2c,      'R211':_2c,
      // R3xx / C3xx / G3xx / D3xx  (R+02 floor — 50 px in table; all get redB)
      'R301':_dt+redB,  'C301':_dt+redB,  'C302':_dt+redB,
      'R302':_dt+redL+redB,
      'R303':_st+redL+redB,  'G303':_st+redL+redB,
      'R304':_2c+redB,       'D304':_2c+redB,
      'R305':_2c+redL+redB,  'R306':_2cf+redL+redB,
    };

    let cells='';
    floors.forEach((fl,fi)=>{
      const isStruct=STRUCT_FLOORS.has(fl);
      cols.forEach((col,ci)=>{
        const type=(types[fl]||[])[ci]||'';
        let s;
        if(isStruct){
          s=`background:${STRUCT_CLR};`;
        }else if(!type){
          s=`background:${JOINT};`;
        }else{
          const pid=`${zid}-${fl}-C${col}`;
          const sb=SC[(panels[pid]||{}).status||'pending']||SC.pending;
          s=`background-color:${sb};`;
          // ── T01-T12: exact patterns from buildComplexTable ───────────────────
          if(type==='T01'){
            s+=`background-image:linear-gradient(180deg,rgba(255,255,255,0.18) 0 33%,transparent 33%);`;
          }else if(type==='T02'){
            s+=`background-image:linear-gradient(180deg,rgba(255,255,255,0.18) 0 33%,transparent 33%);${redB}`;
          }else if(type==='T03'){
            s+=`background-image:linear-gradient(180deg,rgba(255,255,255,0.18) 0 33%,transparent 33%);${redL}`;
          }else if(type==='T04'){
            s+=`background-image:linear-gradient(180deg,rgba(255,255,255,0.18) 0 33%,transparent 33%);${redL}${redB}`;
          }else if(type==='T05'){
            s+=`background-image:${STRIPES};${redL}`;
          }else if(type==='T06'){
            s+=`background-image:${STRIPES};${redL}${redB}`;
          }else if(type==='T07'){
            s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%),${STRIPES};`;
          }else if(type==='T08'){
            s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%),${STRIPES};${redL}`;
          }else if(type==='T09'){
            s+=`background-image:linear-gradient(90deg,transparent 50%,rgba(0,0,0,0.18) 50%),${STRIPES};${redL}`;
          }else if(type==='T10'){
            s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%),${STRIPES};${redB}`;
          }else if(type==='T11'){
            s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%),${STRIPES};${redL}${redB}`;
          }else if(type==='T12'){
            s+=`background-image:linear-gradient(90deg,transparent 50%,rgba(0,0,0,0.18) 50%),${STRIPES};${redL}${redB}`;
          // ── C / D / E / G / M named variants ────────────────────────────────
          }else if(_TM[type]){
            s+=_TM[type];
          // ── R25xx / R34xx / R4xxx: sequential trapezoid codes → colour only ─
          }else if(/^R(25|34)\d{2,}$|^R4\d{3,}$/.test(type)){
            /* status colour only */
          // ── Structural/special types: 3+ digit numeric suffix (R301, R1801…) ─
          }else if(/^[A-Za-z]\d{3,}/.test(type)){
            const sfx=type.slice(-2);
            const pfx=type[0].toUpperCase();
            if(sfx==='01'||sfx==='51'){
              s+=`background-image:${DOTS};background-size:4px 4px;${redB}`;
            }else if(sfx==='02'){
              s+=`background-image:${DOTS};background-size:4px 4px;`;
              s+=pfx==='C'?redB:`${redL}${redB}`;
            }else if(sfx==='52'){
              s+=`background-image:${DOTS};background-size:4px 4px;${redL}${redB}`;
              if(pfx==='E')s+=`border-right:2px solid #ED1C24;`;
            }else if(sfx==='03'||sfx==='53'){
              s+=`background-image:${STRIPES};${redL}${redB}`;
            }else if(sfx==='04'||sfx==='54'){
              s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%);${redB}`;
            }else if(sfx==='05'||sfx==='55'){
              s+=`background-image:linear-gradient(90deg,rgba(0,0,0,0.18) 50%,transparent 50%);${redL}${redB}`;
            }else if(sfx==='06'||sfx==='56'){
              s+=`background-image:${STRIPES};${redL}${redB}`;
            }
            // Other suffixes (R3499, R2581 etc.): status colour only
          }
          // Standard remaining types (Cxx, Dxx, Gxx, Mxx …): status colour only
        }
        cells+=`<div style="${s}"></div>`;
      });
    });

    const gridDiv=`<div style="display:grid;grid-template-columns:${colTpl};grid-template-rows:${rowTpl};gap:${GAP}px;background:${JOINT};width:${w}px;height:${h}px;">${cells}</div>`;
    if(!merges||!merges.length)return gridDiv;
    // Compute row-top and col-left offsets for absolutely-positioned merge overlays
    const rowTops={};let _y=0;
    floors.forEach((fl,fi)=>{rowTops[fl]=_y;_y+=rowHeights[fi]+GAP;});
    const colLefts={};let _x=0;
    cols.forEach((col,ci)=>{colLefts[String(col)]=_x;_x+=CELL+GAP;});
    let overlays='';
    merges.forEach(m=>{
      const fi1=floors.indexOf(m.fl1),fi2=floors.indexOf(m.fl2);
      if(fi1<0||fi2<0)return;
      const mH=rowHeights[fi1]+GAP+rowHeights[fi2];
      const top=rowTops[m.fl1];
      m.mCols.forEach(col=>{
        const left=colLefts[String(col)];
        if(left==null)return;
        const pid=`${zid}-${m.fl1}-C${col}`;
        const clr=SC[(panels[pid]||{}).status||'pending']||SC.pending;
        overlays+=`<div style="position:absolute;left:${left}px;top:${top}px;width:${CELL}px;height:${mH}px;background:${clr};"></div>`;
      });
    });
    return`<div style="position:relative;width:${w}px;height:${h}px;">${gridDiv}${overlays}</div>`;
  }

  // ── Face wrapper: lighting overlay + bottom label ─────────────
  function face(id,transform,w,shade,label,labelColor,content){
    const h=fH;
    const overlay=shade>0?`<div style="position:absolute;inset:0;background:rgba(0,0,0,${shade});pointer-events:none;"></div>`:'';
    const lbl=`<div style="position:absolute;bottom:0;left:0;right:0;padding:3px 0;text-align:center;font-size:9px;font-weight:800;letter-spacing:0.2em;color:${labelColor};background:rgba(0,0,0,0.6);pointer-events:none;text-transform:uppercase;">${label}</div>`;
    return`<div id="${id}" style="position:absolute;width:${w}px;height:${h}px;left:${-w/2}px;top:${-h/2}px;transform:${transform};backface-visibility:hidden;overflow:hidden;outline:1px solid rgba(255,255,255,0.11);">${content}${overlay}${lbl}</div>`;
  }

  // Pre-render grids
  // Row-height override constants (table px → faceRowPx scales by CELL/BASE_W)
  const SMALL_R01={'R+01':25};
  const SMALL_R02={'R+02':50};
  const SMALL_R01_R02={'R+01':25,'R+02':50};
  // NF: cols 65→54 (indices 0-11) — small R+01, normal R+02
  //     cols 53→31 (indices 12-32) — normal R+01, small R+02
  {
    const nfSplit=12;
    const nfSmCols=NF_COLS.slice(0,nfSplit), nfNmCols=NF_COLS.slice(nfSplit);
    const nfTypSm={}, nfTypNm={};
    NF_FLOORS.forEach(fl=>{const r=NF_TYPES[fl]||[];nfTypSm[fl]=r.slice(0,nfSplit);nfTypNm[fl]=r.slice(nfSplit);});
    var nfGrid=`<div style="width:${nfW}px;height:${fH}px;background:${JOINT};display:flex;gap:${GAP}px;align-items:flex-start;">`
      +faceGrid('NF',nfSmCols,NF_FLOORS,nfTypSm,SMALL_R01,[{fl1:'R+02',fl2:'R+01',mCols:[60,59,58]}])
      +faceGrid('NF',nfNmCols,NF_FLOORS,nfTypNm,SMALL_R02)
      +`</div>`;
  }
  // SF: cols 15→1 (indices 0-14) — small R+02; cols 99→81 (indices 15-32) — normal R+02
  {
    const sfSplit=15;
    const sfSmCols=sfCols3D.slice(0,sfSplit), sfNmCols=sfCols3D.slice(sfSplit);
    const sfTypSm={}, sfTypNm={};
    SF_FLOORS.forEach(fl=>{const r=sfTypes3D[fl]||[];sfTypSm[fl]=r.slice(0,sfSplit);sfTypNm[fl]=r.slice(sfSplit);});
    var sfGrid=`<div style="width:${sfW}px;height:${fH}px;background:${JOINT};display:flex;gap:${GAP}px;align-items:flex-start;">`
      +faceGrid('SF',sfSmCols,SF_FLOORS,sfTypSm,SMALL_R02)
      +faceGrid('SF',sfNmCols,SF_FLOORS,sfTypNm)
      +`</div>`;
  }
  // EF: cols 81→79 (indices 0-2) — normal R+01, normal R+02
  //     cols 78→65 (indices 3-16) — small R+01, normal R+02
  {
    const efSplit=3;
    const efNmCols=EF_COLS.slice(0,efSplit), efSmCols=EF_COLS.slice(efSplit);
    const efTypNm={}, efTypSm={};
    EF_FLOORS.forEach(fl=>{const r=EF_TYPES[fl]||[];efTypNm[fl]=r.slice(0,efSplit);efTypSm[fl]=r.slice(efSplit);});
    var efGrid=`<div style="width:${efW}px;height:${fH}px;background:${JOINT};display:flex;gap:${GAP}px;align-items:flex-start;">`
      +faceGrid('EF',efNmCols,EF_FLOORS,efTypNm)
      +faceGrid('EF',efSmCols,EF_FLOORS,efTypSm,SMALL_R01,[{fl1:'R+02',fl2:'R+01',mCols:[75,74,73,71,70,69]}])
      +`</div>`;
  }
  // WF: all columns in range 4-40 — small R+02
  const wfGrid=faceGrid('WF',wfCols3D,WF_FLOORS,wfTypes3D,SMALL_R02);

  // ── Legend ───────────────────────────────────────────────────
  const LEGEND=[
    {label:'Installed',    color:'#00FF32'},
    {label:'Delivered',    color:'#FFF000'},
    {label:'Fabricated',   color:'#002DFF'},
    {label:'CL Issued',    color:'#C98BCA'},
    {label:'CL in Prog.',  color:'#A349A4'},
    {label:'CL Not Issued',color:'#FFB3B3'},
    {label:'Defect',       color:'#ED1C24'},
    {label:'Pending',      color:'#E8F0FB'},
  ];
  const legendHTML=LEGEND.map(l=>`
    <div style="display:flex;align-items:center;gap:4px;">
      <div style="width:11px;height:11px;border-radius:2px;background:${l.color};border:1px solid rgba(255,255,255,0.18);flex-shrink:0;"></div>
      <span style="font-size:10px;color:var(--text2);white-space:nowrap;">${l.label}</span>
    </div>`).join('');

  // ── Roof + ground ────────────────────────────────────────────
  const roof=`<div style="position:absolute;width:${W}px;height:${D}px;left:${-W/2}px;top:${-D/2}px;transform:rotateX(90deg) translateZ(${fH/2}px);backface-visibility:hidden;background:linear-gradient(135deg,#1e2f45,#111c2a);outline:1px solid rgba(255,255,255,0.1);"></div>`;
  const gW=W*2.4,gD=D*2.4;
  const ground=`<div style="position:absolute;width:${gW}px;height:${gD}px;left:${-gW/2}px;top:${-gD/2}px;transform:rotateX(90deg) translateZ(${-fH/2}px);backface-visibility:hidden;background:radial-gradient(ellipse at center,rgba(14,101,169,0.12) 0%,transparent 68%);"></div>`;

  el.innerHTML=`<div class="fpw" style="flex-direction:column;">
    <div style="display:flex;align-items:center;gap:8px;padding:8px 16px;background:var(--surface);border-bottom:1px solid var(--border);flex-shrink:0;flex-wrap:wrap;gap:6px 14px;">
      <span style="font-size:14px;line-height:1;">⭐</span>
      <span style="font-size:13px;font-weight:700;color:var(--text);">3D Facade Overview</span>
      <div style="flex:1;min-width:8px;"></div>
      <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center;">${legendHTML}</div>
      <button onclick="renderAAAPage()" title="Refresh" style="padding:4px 11px;font-size:11px;font-weight:700;background:var(--surface2);border:1px solid var(--border);border-radius:6px;color:var(--text2);cursor:pointer;">↺ Refresh</button>
    </div>
    <div id="aaa-vp" style="flex:1;min-height:0;overflow:hidden;background:radial-gradient(ellipse at 50% 40%,#cde8f8 0%,#a8d4ef 100%);position:relative;cursor:grab;user-select:none;">
      <div id="aaa-scene" style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;perspective:1400px;perspective-origin:50% 48%;">
        <div id="aaa-bld" style="position:relative;width:0;height:0;transform-style:preserve-3d;transform:rotateX(-22deg) rotateY(30deg);">
          ${face('aaa-front', `translateZ(${D/2}px)`,                  nfW, 0,    'North','#60a5fa', nfGrid)}
          ${face('aaa-back',  `rotateY(180deg) translateZ(${D/2}px)`,  sfW, 0.18, 'South','#4ade80', sfGrid)}
          ${face('aaa-east',  `rotateY(-90deg) translateZ(${W/2}px)`,  efW, 0.28, 'East', '#fbbf24', efGrid)}
          ${face('aaa-west',  `rotateY(90deg)  translateZ(${W/2}px)`,  wfW, 0.42, 'West', '#c084fc', wfGrid)}
          ${roof}${ground}
        </div>
      </div>
      <div style="position:absolute;bottom:14px;left:50%;transform:translateX(-50%);background:rgba(0,0,0,0.5);backdrop-filter:blur(6px);color:#6b7f96;font-size:11px;padding:5px 16px;border-radius:20px;pointer-events:none;white-space:nowrap;letter-spacing:0.03em;">
        🖱 Left drag: Pan &nbsp;·&nbsp; Right drag: Orbit &nbsp;·&nbsp; Scroll: Zoom
      </div>
    </div>
  </div>`;

  // ── Interaction ──────────────────────────────────────────────
  const bld=document.getElementById('aaa-bld');
  const vp =document.getElementById('aaa-vp');
  let rotX=-22,rotY=30,zoom=1,panX=0,panY=0;
  let dragging=false,lastX=0,lastY=0;

  function applyT(){
    bld.style.transform=`translate(${panX}px,${panY}px) scale(${zoom}) rotateX(${rotX}deg) rotateY(${rotY}deg)`;
  }

  vp.addEventListener('mousedown',e=>{
    if(e.button!==0)return;
    dragging=true;lastX=e.clientX;lastY=e.clientY;
    vp.style.cursor=e.shiftKey?'grabbing':'move';
    e.preventDefault();
  });
  window.addEventListener('mouseup',()=>{dragging=false;if(vp.isConnected)vp.style.cursor='grab';});
  window.addEventListener('mousemove',e=>{
    if(!dragging)return;
    const dx=e.clientX-lastX,dy=e.clientY-lastY;
    if(e.shiftKey&&e.buttons===1){
      // Shift+Left-click drag → orbit
      rotY+=dx*0.4;rotX-=dy*0.4;
      rotX=Math.max(-88,Math.min(88,rotX));
    }else{
      // Left-click drag → pan
      panX+=dx;panY+=dy;
    }
    lastX=e.clientX;lastY=e.clientY;
    applyT();
  });

  vp.addEventListener('wheel',e=>{
    e.preventDefault();
    zoom*=e.deltaY<0?1.08:0.93;
    zoom=Math.max(0.1,Math.min(7,zoom));
    applyT();
  },{passive:false});

  let lastPinch=0;
  vp.addEventListener('touchstart',e=>{
    e.preventDefault();
    if(e.touches.length===1){lastX=e.touches[0].clientX;lastY=e.touches[0].clientY;}
    if(e.touches.length===2)lastPinch=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
  },{passive:false});
  vp.addEventListener('touchmove',e=>{
    e.preventDefault();
    if(e.touches.length===1){
      // Single finger → pan
      panX+=e.touches[0].clientX-lastX;panY+=e.touches[0].clientY-lastY;
      lastX=e.touches[0].clientX;lastY=e.touches[0].clientY;
      applyT();
    }else if(e.touches.length===2){
      const d=Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
      if(lastPinch){zoom*=d/lastPinch;zoom=Math.max(0.1,Math.min(7,zoom));applyT();}
      lastPinch=d;
    }
  },{passive:false});
}
